import json
import time
import hashlib
import secrets
from datetime import datetime, timedelta
from typing import Optional, Dict, Any

from flask import Flask, request, jsonify
from flask_cors import CORS
from web3 import Web3
from eth_account.messages import encode_defunct
import jwt

app = Flask(__name__)
CORS(app)

# Configuration
app.config['SECRET_KEY'] = secrets.token_hex(32)
app.config['JWT_EXPIRATION_HOURS'] = 24
app.config['NONCE_EXPIRATION_MINUTES'] = 5

# Initialize Web3
w3 = Web3()

# In-memory stores (use Redis/DB in production)
nonce_store: Dict[str, Dict[str, Any]] = {}
session_store: Dict[str, Dict[str, Any]] = {}
user_store: Dict[str, Dict[str, Any]] = {}


class Web3AuthService:
    """Service for handling Web3 wallet-based authentication."""

    @staticmethod
    def generate_nonce(address: str) -> str:
        """Generate a unique nonce for the given address."""
        address = Web3.to_checksum_address(address)
        nonce = secrets.token_hex(16)
        timestamp = time.time()

        nonce_store[address.lower()] = {
            'nonce': nonce,
            'timestamp': timestamp,
            'used': False
        }

        return nonce

    @staticmethod
    def build_sign_message(address: str, nonce: str) -> str:
        """Build the message that the user needs to sign."""
        message = (
            f"Welcome to Web3 Auth Service!\n\n"
            f"Please sign this message to authenticate.\n\n"
            f"Wallet address: {address}\n"
            f"Nonce: {nonce}\n"
            f"Timestamp: {datetime.utcnow().isoformat()}\n\n"
            f"This request will not trigger a blockchain transaction or cost any gas fees."
        )
        return message

    @staticmethod
    def verify_signature(message: str, signature: str, expected_address: str) -> bool:
        """Verify that the signature was created by the expected address."""
        try:
            expected_address = Web3.to_checksum_address(expected_address)
            message_encoded = encode_defunct(text=message)
            recovered_address = w3.eth.account.recover_message(
                message_encoded, signature=signature
            )
            return recovered_address.lower() == expected_address.lower()
        except Exception as e:
            print(f"Signature verification error: {e}")
            return False

    @staticmethod
    def recover_address(message: str, signature: str) -> Optional[str]:
        """Recover the address from a signed message."""
        try:
            message_encoded = encode_defunct(text=message)
            recovered_address = w3.eth.account.recover_message(
                message_encoded, signature=signature
            )
            return Web3.to_checksum_address(recovered_address)
        except Exception as e:
            print(f"Address recovery error: {e}")
            return None

    @staticmethod
    def is_nonce_valid(address: str) -> bool:
        """Check if the nonce for the given address is still valid."""
        address_lower = address.lower()
        if address_lower not in nonce_store:
            return False

        nonce_data = nonce_store[address_lower]
        if nonce_data['used']:
            return False

        elapsed = time.time() - nonce_data['timestamp']
        max_age = app.config['NONCE_EXPIRATION_MINUTES'] * 60
        if elapsed > max_age:
            return False

        return True

    @staticmethod
    def invalidate_nonce(address: str):
        """Mark the nonce as used."""
        address_lower = address.lower()
        if address_lower in nonce_store:
            nonce_store[address_lower]['used'] = True

    @staticmethod
    def generate_jwt(address: str) -> str:
        """Generate a JWT token for the authenticated user."""
        payload = {
            'sub': address.lower(),
            'address': Web3.to_checksum_address(address),
            'iat': datetime.utcnow(),
            'exp': datetime.utcnow() + timedelta(hours=app.config['JWT_EXPIRATION_HOURS']),
            'jti': secrets.token_hex(16)
        }
        token = jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')
        return token

    @staticmethod
    def verify_jwt(token: str) -> Optional[Dict[str, Any]]:
        """Verify and decode a JWT token."""
        try:
            payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
            return payload
        except jwt.ExpiredSignatureError:
            return None
        except jwt.InvalidTokenError:
            return None

    @staticmethod
    def get_or_create_user(address: str) -> Dict[str, Any]:
        """Get or create a user record for the given address."""
        address_lower = address.lower()
        checksum_address = Web3.to_checksum_address(address)

        if address_lower not in user_store:
            user_store[address_lower] = {
                'address': checksum_address,
                'created_at': datetime.utcnow().isoformat(),
                'last_login': datetime.utcnow().isoformat(),
                'login_count': 0
            }

        user = user_store[address_lower]
        user['last_login'] = datetime.utcnow().isoformat()
        user['login_count'] += 1

        return user


auth_service = Web3AuthService()


def require_auth(f):
    """Decorator to require JWT authentication."""
    from functools import wraps

    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid authorization header'}), 401

        token = auth_header.split('Bearer ')[1]
        payload = auth_service.verify_jwt(token)

        if payload is None:
            return jsonify({'error': 'Invalid or expired token'}), 401

        request.user = payload
        return f(*args, **kwargs)

    return decorated


def is_valid_eth_address(address: str) -> bool:
    """Validate an Ethereum address."""
    try:
        Web3.to_checksum_address(address)
        return True
    except (ValueError, Exception):
        return False


# ============ API Routes ============

@app.route('/api/auth/nonce', methods=['POST'])
def request_nonce():
    """
    Step 1: Client requests a nonce for their wallet address.
    The nonce is used to create a unique message for signing.
    """
    data = request.get_json()
    if not data or 'address' not in data:
        return jsonify({'error': 'Wallet address is required'}), 400

    address = data['address']

    if not is_valid_eth_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    checksum_address = Web3.to_checksum_address(address)
    nonce = auth_service.generate_nonce(checksum_address)
    message = auth_service.build_sign_message(checksum_address, nonce)

    return jsonify({
        'success': True,
        'address': checksum_address,
        'nonce': nonce,
        'message': message,
        'expires_in': app.config['NONCE_EXPIRATION_MINUTES'] * 60
    })


@app.route('/api/auth/verify', methods=['POST'])
def verify_signature():
    """
    Step 2: Client submits the signed message for verification.
    If valid, returns a JWT token for subsequent requests.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    required_fields = ['address', 'signature', 'message']
    for field in required_fields:
        if field not in data:
            return jsonify({'error': f'{field} is required'}), 400

    address = data['address']
    signature = data['signature']
    message = data['message']

    if not is_valid_eth_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    checksum_address = Web3.to_checksum_address(address)

    # Check nonce validity
    if not auth_service.is_nonce_valid(checksum_address):
        return jsonify({'error': 'Nonce expired or invalid. Please request a new nonce.'}), 401

    # Recover the address from the signature
    recovered_address = auth_service.recover_address(message, signature)

    if recovered_address is None:
        return jsonify({'error': 'Failed to recover address from signature'}), 401

    # Verify the recovered address matches the claimed address
    if recovered_address.lower() != checksum_address.lower():
        return jsonify({
            'error': 'Signature verification failed. Recovered address does not match.',
            'expected': checksum_address,
            'recovered': recovered_address
        }), 401

    # Verify signature directly
    is_valid = auth_service.verify_signature(message, signature, checksum_address)

    if not is_valid:
        return jsonify({'error': 'Invalid signature'}), 401

    # Invalidate the nonce (one-time use)
    auth_service.invalidate_nonce(checksum_address)

    # Get or create user
    user = auth_service.get_or_create_user(checksum_address)

    # Generate JWT
    token = auth_service.generate_jwt(checksum_address)

    return jsonify({
        'success': True,
        'token': token,
        'address': checksum_address,
        'user': user,
        'expires_in': app.config['JWT_EXPIRATION_HOURS'] * 3600
    })


