@app.route('/api/user/profile', methods=['PUT'])
@require_auth
def update_profile():
    """Update the authenticated user's profile."""
    address = request.user['address']
    address_lower = address.lower()
    data = request.get_json()

    if address_lower not in user_store:
        return jsonify({'error': 'User not found'}), 404

    allowed_fields = ['username', 'email', 'bio', 'avatar_url']
    for field in allowed_fields:
        if field in data:
            user_store[address_lower][field] = data[field]

    user_store[address_lower]['updated_at'] = datetime.utcnow().isoformat()

    return jsonify({
        'success': True,
        'user': user_store[address_lower]
    })


